function showVideo() {
    const video = document.getElementById("birthday-video");
    const container = document.getElementById("video-screen");
    
    fadeOutIn("gift-box-screen", "video-screen");
    
    // Ensure video end message is hidden when starting
    document.getElementById("video-end-msg").classList.add("hidden");
    
    // Attempt play
    setTimeout(() => {
        video.currentTime = 0;
        video.play().catch(e => {
            console.warn("Video play blocked or failed:", e);
        });
    }, 1100); // Wait for fade in
    
    video.onended = function() {
        document.getElementById("video-end-msg").classList.remove("hidden");
    };
    
    window.scrollTo({ top: 0, behavior: 'smooth' });
}

