function pickReasonFromJar() {
    const jar = document.querySelector('.jar');
    const display = document.getElementById("reason-display");
    
    // Animation
    jar.style.animation = "shake 0.5s ease";
    setTimeout(() => jar.style.animation = "", 500);
    
    const randomReason = reasons[Math.floor(Math.random() * reasons.length)];
    display.style.opacity = "0";
    setTimeout(() => {
        display.innerHTML = `<p>${randomReason}</p>`;
        display.style.opacity = "1";
    }, 300);
}

function showOurSky() {
    openModal("sky-modal");
    generateStars();
}

function generateStars() {
    const sky = document.getElementById("constellation-sky");
    // Clear existing sky stars if any (except the date/msg)
    const existingStars = sky.querySelectorAll('.sky-star');
    existingStars.forEach(s => s.remove());

    for (let i = 0; i < 150; i++) {
        const star = document.createElement("div");
        star.className = "sky-star";
        const size = Math.random() * 3 + 1;
        star.style.width = `${size}px`;
        star.style.height = `${size}px`;
        star.style.left = `${Math.random() * 100}%`;
        star.style.top = `${Math.random() * 100}%`;
        star.style.setProperty('--t', `${Math.random() * 3 + 2}s`);
        star.style.animationDelay = `${Math.random() * 5}s`;
        sky.appendChild(star);
    }
}

function goBack(curr, prev) {
    if (curr === "video-screen") document.getElementById("birthday-video").pause();
    fadeOutIn(curr, prev);
}

function createSparkles() {
    const container = document.body;
    const items = ['✨', '💙', '🌌', '💧', '⭐', '🦋', '🌙'];
    for (let i = 0; i < 50; i++) {
        const sparkle = document.createElement("div");
        sparkle.className = "sparkle";
        const item = items[Math.floor(Math.random() * items.length)];
        sparkle.innerHTML = item;
        sparkle.style.fontSize = `${Math.random() * 20 + 10}px`;
        sparkle.style.background = "none";

        const duration = Math.random() * 8 + 5;
        sparkle.style.setProperty('--d', `${duration}s`);
        sparkle.style.left = `${Math.random() * 100}vw`;
        sparkle.style.top = `${Math.random() * 100}vh`;
        sparkle.style.animationDelay = `${Math.random() * 5}s`;
        container.appendChild(sparkle);
    }
}

function initCursorTrail() {
    document.addEventListener('mousemove', (e) => {
        if (Math.random() > 0.1) return; // Only create sometimes
        const heart = document.createElement('div');
        heart.innerHTML = '💙';
        heart.style.position = 'fixed';
        heart.style.left = e.clientX + 'px';
        heart.style.top = e.clientY + 'px';
        heart.style.fontSize = (Math.random() * 10 + 10) + 'px';
        heart.style.pointerEvents = 'none';
        heart.style.opacity = '0.6';
        heart.style.zIndex = '10000';
        heart.style.transition = 'all 1.5s ease-out';
        heart.style.transform = `translate(${(Math.random() - 0.5) * 50}px, ${Math.random() * 50}px) rotate(${Math.random() * 360}deg)`;
        
        document.body.appendChild(heart);
        
        setTimeout(() => {
            heart.style.opacity = '0';
            heart.style.transform += ' translateY(30px) scale(0)';
        }, 50);
        
        setTimeout(() => heart.remove(), 1500);
    });
}

function toggleMusic() {
    const audio = document.getElementById("bg-audio");
    const icon = document.querySelector("#music-toggle .icon");
    if (audio.paused) {
        audio.play().then(() => {
            icon.innerText = "🎵";
        }).catch(e => {
            console.error("Music play failed:", e);
            alert("Please interact with the page first to enable music! 💙");
        });
    } else {
        audio.pause();
        icon.innerText = "🔇";
    }
}

function setupAudioSync() {
    const audio = document.getElementById("bg-audio");
    const icon = document.querySelector("#music-toggle .icon");
    if (audio && icon) {
        audio.onplay = () => icon.innerText = "🎵";
        audio.onpause = () => icon.innerText = "🔇";
        // Sync initial state
        icon.innerText = audio.paused ? "🔇" : "🎵";
    }
}

if (document.readyState === 'loading') {
    window.addEventListener('DOMContentLoaded', setupAudioSync);
} else {
    setupAudioSync();
}

createSparkles();
initCursorTrail();
initGallery();

